      registerCityParallaxLayer(sideLayerNear, { axis: "side", baseOpacity: 0.25, parallaxX: 0.34, parallaxY: 0.08, mapDrift: 0.0035, phase: 2.8, floatAmp: 0.022 });

      const windowSoftLight = new THREE.PointLight(0x557ea8, 0.26, 7.8, 2.0);
      windowSoftLight.position.set(-1.15, 2.92, -2.62);
