      const hemi = new THREE.HemisphereLight(0x8faeca, 0x081018, 0.68);
      scene.add(hemi);

      const keyLight = new THREE.DirectionalLight(0xe1e8f0, 1.22);
      keyLight.position.set(4.2, 7.8, -3.8);
