      function certificatePaperTexture() {
        return makeTexture(512, (ctx, w, h) => {
          const base = ctx.createLinearGradient(0, 0, w, h);
          base.addColorStop(0, "#cfd6df");
          base.addColorStop(0.50, "#c5ced8");
          base.addColorStop(1, "#b9c3cf");
          ctx.fillStyle = base;
          ctx.fillRect(0, 0, w, h);
          const center = ctx.createRadialGradient(w * 0.48, h * 0.42, 0, w * 0.48, h * 0.42, w * 0.62);
          center.addColorStop(0, "rgba(255,255,255,0.060)");
          center.addColorStop(0.62, "rgba(255,255,255,0.010)");
          center.addColorStop(1, "rgba(8,18,32,0.145)");
          ctx.fillStyle = center;
          ctx.fillRect(0, 0, w, h);
          for (let i = 0; i < 2600; i++) {
            const v = 150 + Math.random() * 72;
            const a = Math.random() * 0.028;
            ctx.fillStyle = `rgba(${v},${v},${v},${a})`;
            ctx.fillRect(Math.random() * w, Math.random() * h, 1, 1);
          }
          ctx.strokeStyle = "rgba(82, 104, 128, 0.115)";
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(w * 0.17, h * 0.22);
          ctx.lineTo(w * 0.50, h * 0.22);
          ctx.stroke();

          ctx.strokeStyle = "rgba(70, 95, 122, 0.080)";
          ctx.lineWidth = 1.1;
          for (let i = 0; i < 3; i++) {
            ctx.beginPath();
            ctx.moveTo(w * 0.18, h * (0.35 + i * 0.065));
            ctx.lineTo(w * (0.56 - i * 0.05), h * (0.35 + i * 0.065));
            ctx.stroke();
          }
          ctx.strokeStyle = "rgba(70, 96, 126, 0.105)";
          ctx.lineWidth = 2.2;
          ctx.beginPath();
          ctx.arc(w * 0.72, h * 0.66, w * 0.055, 0, Math.PI * 2);
          ctx.stroke();

          ctx.strokeStyle = "rgba(70, 96, 126, 0.070)";
          ctx.lineWidth = 1;
          ctx.beginPath();
          ctx.moveTo(w * 0.61, h * 0.80);
          ctx.lineTo(w * 0.81, h * 0.80);
          ctx.stroke();
          ctx.strokeStyle = "rgba(13, 26, 43, 0.080)";
          ctx.lineWidth = 10;
          ctx.strokeRect(4, 4, w - 8, h - 8);
        });
      }

      function certificatePaperRoughnessTexture() {
        return makeTexture(512, (ctx, w, h) => {
          ctx.fillStyle = "rgb(222,222,222)";
          ctx.fillRect(0, 0, w, h);
          for (let i = 0; i < 3600; i++) {
            const v = 168 + Math.random() * 62;
            const a = Math.random() * 0.065;
            ctx.fillStyle = `rgba(${v},${v},${v},${a})`;
            ctx.fillRect(Math.random() * w, Math.random() * h, 1, 1);
          }
          const edge = ctx.createRadialGradient(w * 0.5, h * 0.45, w * 0.08, w * 0.5, h * 0.45, w * 0.66);
          edge.addColorStop(0, "rgba(255,255,255,0.040)");
          edge.addColorStop(1, "rgba(80,80,80,0.105)");
          ctx.fillStyle = edge;
          ctx.fillRect(0, 0, w, h);
        });
      }

