        const mat = index === total - 1 ? paperStackTopMat : paperStackUnderMat;
        sheet.add(mesh(new THREE.BoxGeometry(width, height, 0.0062), mat, [0, 0, 0]));
        sheet.add(mesh(new THREE.BoxGeometry(width * 0.98, 0.011, 0.007), paperStackSideMat, [0, -height * 0.49, -0.001]));
        sheet.add(mesh(new THREE.BoxGeometry(0.011, height * 0.84, 0.007), paperStackSideMat, [width * 0.49, -height * 0.035, -0.001]));
